import { createDiagnosticCollector, getLocationContext, navigateProgram } from "@typespec/compiler";
import { expectDiagnostics } from "@typespec/compiler/testing";
import { beforeEach, describe, it } from "vitest";
import { Tester } from "../testing/test-host.js";
import { singleBlockFormRule } from "./single-block-form.rule.js";

async function runRuleDiagnostics(
  runner: Awaited<ReturnType<typeof Tester.createInstance>>,
  code: string | Record<string, string>,
) {
  await runner.compileAndDiagnose(code);
  const collector = createDiagnosticCollector();
  const ruleId = `@a10n/blueprint-typespec/${singleBlockFormRule.name}`;
  const messages = singleBlockFormRule.messages as Record<string, any>;
  const context = {
    program: runner.program,
    reportDiagnostic(diag: { messageId?: string; format?: Record<string, string>; target: any }) {
      const msgDef = messages[diag.messageId ?? "default"];
      const messageStr = typeof msgDef === "string" ? msgDef : msgDef(diag.format ?? {});
      const locCtx = getLocationContext(runner.program, diag.target);
      if (locCtx.type === "project") {
        collector.add({ code: ruleId, severity: singleBlockFormRule.severity, message: messageStr, target: diag.target } as any);
      }
    },
  };
  const listener = singleBlockFormRule.create(context as any);
  navigateProgram(runner.program, listener);
  return collector.diagnostics;
}

describe("single-block-form rule", () => {
  let runner: Awaited<ReturnType<typeof Tester.createInstance>>;

  beforeEach(async () => {
    runner = await Tester.createInstance();
  });

  // ── no diagnostic cases ───────────────────────────────────────────────────

  // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_single_block_form
  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T022.T022_01
  it("T022_01: single file, single block-form namespace — no diagnostic", async () => {
    const diags = await runRuleDiagnostics(runner, `
      namespace Components.Foo {
        model M { x: string; }
      }
    `);
    expectDiagnostics(diags, []);
  });

  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T022.T022_02
  it("T022_02: two files, both bare semicolon form — no diagnostic", async () => {
    const diags = await runRuleDiagnostics(runner, {
      "main.tsp": `
        import "./other.tsp";
        namespace Components.Foo;
        model A { x: string; }
      `,
      "other.tsp": `
        namespace Components.Foo;
        model B { y: string; }
      `,
    });
    expectDiagnostics(diags, []);
  });

  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T022.T022_03
  it("T022_03: one block-form file plus bare-form augmenting file — no diagnostic", async () => {
    const diags = await runRuleDiagnostics(runner, {
      "main.tsp": `
        import "./other.tsp";
        namespace Components.Foo {
          model A { x: string; }
        }
      `,
      "other.tsp": `
        namespace Components.Foo;
        model B { y: string; }
      `,
    });
    expectDiagnostics(diags, []);
  });

  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T022.T022_04
  it("T022_04: distinct FQNs each in block form — no diagnostic", async () => {
    const diags = await runRuleDiagnostics(runner, {
      "main.tsp": `
        import "./other.tsp";
        namespace Components.Foo {
          model A { x: string; }
        }
      `,
      "other.tsp": `
        namespace Components.Bar {
          model B { y: string; }
        }
      `,
    });
    expectDiagnostics(diags, []);
  });

  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T022.T022_05
  it("T022_05: nested block forms with distinct FQNs in one file — no diagnostic", async () => {
    const diags = await runRuleDiagnostics(runner, `
      namespace Outer {
        namespace Inner {
          model M { x: string; }
        }
      }
    `);
    expectDiagnostics(diags, []);
  });

  // ── diagnostic cases ──────────────────────────────────────────────────────

  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T022.T022_06
  it("T022_06: same FQN in block form in two files — diagnostic on the second", async () => {
    const diags = await runRuleDiagnostics(runner, {
      "main.tsp": `
        import "./other.tsp";
        namespace Components.Foo {
          model A { x: string; }
        }
      `,
      "other.tsp": `
        namespace Components.Foo {
          model B { y: string; }
        }
      `,
    });
    expectDiagnostics(diags, [
      { code: "@a10n/blueprint-typespec/single-block-form", message: /Components\.Foo/ },
    ]);
  });

  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T022.T022_07
  it("T022_07: empty block form in one file plus block form with content in another — diagnostic on the second", async () => {
    const diags = await runRuleDiagnostics(runner, {
      "main.tsp": `
        import "./other.tsp";
        @doc("a")
        namespace Components.Foo {}
      `,
      "other.tsp": `
        namespace Components.Foo {
          model M { x: string; }
        }
      `,
    });
    expectDiagnostics(diags, [
      { code: "@a10n/blueprint-typespec/single-block-form", message: /Components\.Foo/ },
    ]);
  });

  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T022.T022_09
  it("T022_09: flags the LATER-processed block (the overwriter), references the earlier file in the message", async () => {
    // TypeSpec INSERT-OR-REPLACE: the LAST-processed file's block-form
    // declaration overwrites the earlier file's symbol entry, silently
    // dropping its decorators. The rule must flag the OVERWRITER
    // (later-processed) so the dev fixes the right file — the one that
    // should be converted to bare `namespace X;`. The earlier
    // declaration is what we want to keep as canonical, so it must NOT
    // be flagged. The diagnostic message should reference the earlier
    // file (the one being overwritten) for context.
    const diags = await runRuleDiagnostics(runner, {
      // main.tsp imports other.tsp ⇒ main.tsp's NS is processed first.
      // other.tsp is processed last ⇒ other.tsp's block overwrites
      // main.tsp's @doc, dropping it. Rule flags other.tsp.
      "main.tsp": `
        import "./other.tsp";
        @doc("decorators-on-main")
        namespace Components.Foo {
          model A { x: string; }
        }
      `,
      "other.tsp": `
        namespace Components.Foo {
          model B { y: string; }
        }
      `,
    });
    // Exactly one diagnostic; message references main.tsp (the
    // earlier, decorator-bearing file).
    expectDiagnostics(diags, [
      {
        code: "@a10n/blueprint-typespec/single-block-form",
        message: /Components\.Foo.*main\.tsp/,
      },
    ]);
  });

  // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T022.T022_08
  it("T022_08: three files in block form for same FQN — two diagnostics", async () => {
    const diags = await runRuleDiagnostics(runner, {
      "main.tsp": `
        import "./b.tsp";
        import "./c.tsp";
        namespace Components.Foo {
          model A { x: string; }
        }
      `,
      "b.tsp": `
        namespace Components.Foo {
          model B { y: string; }
        }
      `,
      "c.tsp": `
        namespace Components.Foo {
          model C { z: string; }
        }
      `,
    });
    expectDiagnostics(diags, [
      { code: "@a10n/blueprint-typespec/single-block-form", message: /Components\.Foo/ },
      { code: "@a10n/blueprint-typespec/single-block-form", message: /Components\.Foo/ },
    ]);
  });
});
